const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set',
    parameters: {
      assignments: {
        assignments: []
      },
      options: {}
    }
  }
});

export default workflow('scaffold', 'Manual Trigger + Set Node Scaffold')
  .add(manualTrigger)
  .to(setNode);
